/*
 * std::vector<std::string>::~vector()
 *
 * Destroys every std::string element in the vector, then frees the
 * underlying storage. This mirrors what libstdc++ inlines for the
 * destructor of vector<basic_string<char>>:
 *
 *   for (string* p = _M_start; p != _M_finish; ++p)
 *       p->~basic_string();           // calls operator delete on the
 *                                     // heap buffer iff it is not the
 *                                     // SSO buffer (p + 16).
 *   if (_M_start)
 *       operator delete(_M_start, _M_end_of_storage - _M_start);
 */
void std__vector_string__dtor(std__vector_string *self)
{
    std__string *first  = self->_M_start;
    std__string *last   = self->_M_finish;

    /* Destroy each contained std::string. */
    for (std__string *p = first; p != last; ++p) {
        /* basic_string stores a pointer to its data; if that pointer
         * doesn't point at the embedded SSO buffer (p->_M_local_buf,
         * which lives at offset 16 from the string object), the heap
         * buffer must be released. */
        if (p->_M_dataplus._M_p != (char *)&p->_M_local_buf) {
            operator_delete(p->_M_dataplus._M_p);
        }
    }

    /* Free the array of std::string objects, if any was allocated. */
    if (first != NULL) {
        size_t bytes = (size_t)((char *)self->_M_end_of_storage
                              - (char *)first);
        operator_delete(first, bytes);
    }
}

